const j = $input.first().json.chatInput

// Telegram suele traer el texto aquí:
const text =
  (j.message?.text || j.message?.caption || '').trim();

if (!text) {
  throw new Error('No hay texto en el mensaje.');
}

// max=200 (opcional)
const maxToken = text.match(/(?:^|\s)max\s*=\s*(\d+)/i);
let maxProducts = 200;
if (maxToken?.[1]) {
  const n = parseInt(maxToken[1], 10);
  if (Number.isFinite(n)) maxProducts = Math.min(Math.max(n, 1), 2000);
}

// Extraer URL (acepta https://, http://, //dominio, www., o dominio “a pelo”)
let url = '';
const urlMatch = text.match(/https?:\/\/[^\s]+|\/\/[^\s]+|www\.[^\s]+|[a-z0-9.-]+\.[a-z]{2,}(?:\/[^\s]*)?/i);
if (urlMatch) url = urlMatch[0].trim();

if (!url) {
  throw new Error('No encontré ninguna URL. Ej: https://fonestar.com max=200');
}

// Normalizar URL
if (url.startsWith('//')) url = 'https:' + url;
if (url.startsWith('www.')) url = 'https://' + url;
if (!/^https?:\/\//i.test(url)) url = 'https://' + url;

// Validar + calcular origin
let origin = '';
try {
  origin = new URL(url).origin;
} catch (e) {
  throw new Error(`URL inválida: ${url}`);
}

const chatId = j.message?.chat?.id;

return [{
  json: {
    chatId,
    inputText: text,
    targetUrl: url,
    origin,
    maxProducts,
    userAgent: 'Mozilla/5.0 (n8n-scraper)'
  }
}];
